INSERT INTO articles (id, title, category, target_audience, content_summary, status, related_gear_ids, related_facility_ids) VALUES ('article_pb_101', '【図解】5分でわかる！ピックルボールのルールとスコアの数え方完全ガイド', '初心者ガイド', '初心者', 'ピックルボールの基本的なルール（ツーバウンスルール、ノンボレーゾーン、独特なスコアの数え方）を図解入りで分かりやすく解説する入門記事。', 'published', '[]', '[]');
INSERT INTO articles (id, title, category, target_audience, content_summary, status, related_gear_ids, related_facility_ids) VALUES ('article_paddle_core_thickness', 'パワフルに打ちたい？それともコントロール？「コア厚（14mm vs 16mm）」の徹底比較', 'ギアレビュー', '中級者', 'パドル選びで最も迷うポイントである「コア厚」。14mmの弾きとパワー、16mmのコントロールと衝撃吸収性の違いをプロのインプレッションを交えて解説。', 'published', '["paddle_joola_perseus","paddle_franklin_fs_tour"]', '[]');
INSERT INTO articles (id, title, category, target_audience, content_summary, status, related_gear_ids, related_facility_ids) VALUES ('article_strategy_third_shot_drop', 'DUPR 3.5の壁を越える！「サードショット・ドロップ」成功率を劇的に上げる5つのコツ', '戦術・ドリル', '中級者', '試合をコントロールするために必須の「サードショットドロップ」。ネットの頂点を狙うのではなく、キッチンに落とすための軌道イメージやグリップの握りを解説。', 'published', '[]', '[]');
INSERT INTO articles (id, title, category, target_audience, content_summary, status, related_gear_ids, related_facility_ids) VALUES ('article_local_kanto_night', '【東京/関東版】仕事帰りに寄れる！ナイター設備・レンタル完備のピックルボールコート10選', 'ローカル情報', '全員', '平日夜に手ぶらで通える東京都内・近郊のピックルボール施設を厳選して紹介。パドルレンタルやシャワーの有無、アクセス情報をまとめた保存版記事。', 'published', '[]', '["facility_tokyotower","facility_viptop","facility_pacific_pickle"]');
INSERT INTO articles (id, title, category, target_audience, content_summary, status, related_gear_ids, related_facility_ids) VALUES ('article_news_ppa_mlp', 'PPAとMLPって何が違うの？世界のピックルボールプロリーグ基礎知識と視聴方法', 'ニュース・プロ動向', '観戦・ファン', 'アメリカを中心に爆発的な人気を誇るプロリーグ「PPAツアー」と「メジャーリーグピックルボール(MLP)」のフォーマットの違い、注目選手、日本からの視聴方法を解説。', 'published', '[]', '[]');
