INSERT INTO beginner_guide (id, title, target_audience, content_summary, related_youtube_url, key_takeaways) VALUES ('art_beginner_rule_score', '【図解】5分でわかる！ピックルボールのルールとスコアの数え方完全ガイド', '初心者', 'ピックルボール最大の特徴である「サイドアウト制」によるスコアの数え方（自分-相手-サーバー番号 の3つの数字のコール）や、ノンボレーゾーン（キッチン）のルールをわかりやすく解説します。11点先取で2点差をつける基本ルールから、ダブルスとシングルスの違いまで網羅。', 'https://www.youtube.com/results?search_query=ピックルボール+得点+数え方', '["スコアはサーブ権を持っている時のみ入る（サイドアウト制）","最初のスコアコールは「0-0-2」から始まる","キッチン（ネット際）ではノーバウンドでボレーを打ってはいけない"]');
INSERT INTO beginner_guide (id, title, target_audience, content_summary, related_youtube_url, key_takeaways) VALUES ('art_beginner_tennis_transition', 'テニス経験者必見！ピックルボール転向時に活きる技術と捨てるべきクセ', '初心者（テニスなど他ラケットスポーツ経験者）', 'テニス経験者がピックルボールを始める際、テニスの大きなテイクバックは不要なため、スイングをコンパクトにする必要があります。また、ボレーもステップインしすぎるとフットフォルトになるため、スクエアに構えてパンチするコツや、強打に頼らずディンクやドロップで忍耐強く繋ぐ戦略の重要性を説きます。', 'https://www.youtube.com/results?search_query=テニス経験者+ピックルボール+コツ', '["テイクバックを小さくし、コンパクトなスイングを心がける","キッチンラインでのボレーはステップインしすぎない","強打よりも「ディンク」や「サードショットドロップ」の忍耐力が勝負を決める"]');
INSERT INTO beginner_guide (id, title, target_audience, content_summary, related_amazon_search, key_takeaways, related_gear_ids) VALUES ('art_beginner_first_paddle', '【2026年最新】初心者に絶対おすすめのスターターパドルと選び方', '初心者', '初心者が最初に買うべきパドルは、操作性の高い軽量〜中量級（210g〜240g）で、スイートスポットが広いワイドボディタイプ、厚さ16mmのものが無難です。JOOLA EssentialsやONIX Z5 Graphiteなどの代表的な初心者向けモデルと、Amazon等での賢い買い方を紹介します。', 'https://www.amazon.co.jp/s?k=ピックルボール+パドル+初心者', '["初心者には軽量でコントロールしやすいグラファイト（カーボン）素材がおすすめ","ミスを減らすため、厚さ16mmでスイートスポットの広いモデルを選ぶ","最初は高価なハイエンドモデルではなく、バランスの良いエントリーモデルから始める"]', '["paddle_joola_essentials","paddle_onix_z5"]');
