INSERT INTO gear_reviews (id, title, published_at, author, content, tags, view_count) VALUES ('article_gen_gear_30', 'ハイエンドパドル徹底レビュー 30: プロが教える秘訣', '2026-03-21T10:00:00Z', 'Pickle_Pro_4', 'ピックルボールのハイエンドパドル徹底レビューに関する詳細な解説記事です。最新のトレンドや基礎基本を網羅しています...', '["gear","ピックルボール","解説"]', 3216);
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_kitchen', 'Kitchen / Non-Volley Zone (NVZ)', 'キッチン / ノンボレーゾーン', 'コート・ルール', 'ネットの両側7フィート（約2.13m）のエリア。このエリア内（ライン上を含む）では、ノーバウンドでの返球（ボレー）が禁止されている。ピックルボール最大の特徴。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_dink', 'Dink', 'ディンク', 'ショット', 'キッチンライン付近から、相手のキッチン内に優しく山なりに落とすコントロールショット。相手に攻撃させないための最も重要な戦術。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_third_shot_drop', 'Third Shot Drop', 'サードショット・ドロップ', '戦術・ショット', 'サーブ権を持つ側が打つ3球目のショットで、相手のキッチン内に落として前進する時間を作る高度な技術。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_reset', 'Reset', 'リセット', '戦術', '相手からの強い攻撃（ドライブ等）を柔らかくブロックし、再びキッチン内にボールを落としてラリーのペースを落ち着かせること。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_erne', 'Erne', 'アーネ', 'ショット', 'ノンボレーゾーンの外側を回り込み、コートの横から飛び出してネット際でボレーを打つ超攻撃的なショット。名前は発案者のErne Perryに由来する。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_atp', 'ATP (Around The Post)', 'ATP（アラウンド・ザ・ポスト）', 'ショット', 'ネットポスト（支柱）の外側を通して相手コートにボールを入れるショット。ルール上ネットの上を通す必要がないため有効。角度のついた返球に対する反撃手段。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_volley', 'Volley', 'ボレー', 'ショット', 'ボールがバウンドする前に空中で打ち返すショット。キッチン（NVZ）内では禁止されている。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_drive', 'Drive', 'ドライブ', 'ショット', '低く速い弾道で打つ攻撃的なストローク。相手の反応時間を奪い、ミスを誘う際に使用される。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_lob', 'Lob', 'ロブ', 'ショット', '高い弧を描いて相手の頭上を越すショット。ネット前に詰めた相手の体勢を崩す戦術。ディフェンスにも攻撃にも使用可能。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_drop_shot', 'Drop Shot', 'ドロップショット', 'ショット', 'ボールを柔らかく打ち、相手のキッチン付近にふわりと落とすショット。ネットに近づくための時間を稼ぐ目的で多用される。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_serve', 'Serve', 'サーブ', 'ルール・ショット', 'ラリーを開始する最初のショット。アンダーハンド（下から）で打つ必要があり、ウエストより下の高さで打球しなければならない。対角線のサービスコートに入れる。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_return_of_serve', 'Return of Serve', 'リターン', 'ショット', 'サーブを受けた側が打つ2球目のショット。深く返してサーブ側の前進を遅らせるのが基本戦術。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_two_bounce_rule', 'Two-Bounce Rule / Double Bounce Rule', 'ツーバウンスルール', 'ルール', 'サーブとリターンはそれぞれ必ず1バウンドしてから打たなければならないルール。3球目以降はボレーOK（キッチン外に限る）。旧称ダブルバウンスルール。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_side_out', 'Side Out', 'サイドアウト', 'ルール', 'サーブ権が相手チームに移ること。ダブルスでは2人ともサーブを失敗した後にサイドアウトとなる（ゲーム最初のサーブ側は1人のみ）。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_rally_scoring', 'Rally Scoring', 'ラリースコアリング', 'ルール', 'サーブ権に関係なく、ラリーに勝った側に得点が入るスコアリング方式。MLPなどのプロリーグで採用され、試合のテンポアップを目的とする。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_traditional_scoring', 'Traditional Scoring / Side-Out Scoring', 'サイドアウトスコアリング（従来方式）', 'ルール', 'サーブ権を持つ側のみが得点できる伝統的なスコアリング方式。通常11点先取（2点差必要）で行われる。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_stacking', 'Stacking', 'スタッキング', '戦術', 'ダブルスで、強いフォアハンドを中央に配置するためにサーブやリターン時にポジションを入れ替える高度な陣形戦術。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_poach', 'Poach', 'ポーチ', '戦術', 'ダブルスで、パートナー側に来たボールを横から飛び出して打ちに行く積極的な攻撃。相手の意表を突く効果がある。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_speed_up', 'Speed-up', 'スピードアップ', '戦術・ショット', 'ディンクラリーなどの低速な展開から突然速い攻撃ショットを仕掛けること。タイミングと狙い所が重要。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_firefight', 'Firefight / Hands Battle', 'ファイヤーファイト / ハンドバトル', '戦術', 'ネット近くで超高速の打ち合いが連続する場面。反射神経と手首のコントロールが試される白熱の展開。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_punch_volley', 'Punch Volley', 'パンチボレー', 'ショット', '相手の攻撃に対し、短いスイングで力強く押し返すボレー。守備から攻撃に即座に転じる際に有効。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_roll_volley', 'Roll Volley', 'ロールボレー', 'ショット', 'トップスピンをかけながら打つボレー。相手の足元に沈むため攻撃的なフィニッシュショットとして使われる。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_backhand_flick', 'Backhand Flick', 'バックハンドフリック', 'ショット', 'バックハンド側に来たボールを手首のスナップで素早く弾くショット。ハンドバトル時やスピードアップに多用される。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_bert', 'Bert', 'バート', 'ショット', 'パートナーの後ろ側を回り込んでアーネ（Erne）を行う高度なダブルス専用ショット。究極のチームワークが必要。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_nasty_nelson', 'Nasty Nelson', 'ナスティ・ネルソン', '戦術', 'サーブを意図的にレシーバーではなくそのパートナー（非レシーバー）に当てる戦術。当たった場合はサーバー側の得点となる。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_dupr', 'DUPR (Dynamic Universal Pickleball Rating)', 'DUPR（ダイナミック・ユニバーサル・ピックルボール・レーティング）', 'レーティング・大会', '世界標準のピックルボールレーティングシステム。2.0〜8.0のスケールで全プレイヤーのスキルレベルを数値化。試合結果に基づき自動算出される。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_utpr', 'UTPR (USA Pickleball Tournament Player Rating)', 'UTPR', 'レーティング・大会', 'USA Pickleball（旧USAPA）が管理するトーナメントベースのレーティング。公式大会のみの成績で算出される4桁の数値。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_ppa', 'PPA Tour (Professional Pickleball Association)', 'PPAツアー', '大会・リーグ', '世界最高峰のプロピックルボールツアー。年間を通じて全米各地で大会を開催し、トッププロが賞金を懸けて戦う。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_mlp', 'MLP (Major League Pickleball)', 'MLP（メジャーリーグ・ピックルボール）', '大会・リーグ', 'チーム対抗形式のプロリーグ。セレブリティがチームオーナーを務め、ラリースコアリングを採用。エンターテインメント性も高い。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_app', 'APP Tour (Association of Pickleball Professionals)', 'APPツアー', '大会・リーグ', 'PPAと並ぶプロツアー組織。PPAとの統合が進行中。アマチュア部門も充実しており参加しやすい。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_usap', 'USA Pickleball (USAP / USAPA)', 'USAピックルボール', '組織', '米国ピックルボール統括団体。公式ルールの策定、用具の認証、トーナメントの認定を行う最高権威。旧称USAPA。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_jpa', 'JPA (Japan Pickleball Association)', 'JPA（日本ピックルボール協会）', '組織', '日本国内のピックルボール統括団体。国内大会の主催、選手の育成、普及活動を行っている。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_paddle', 'Paddle', 'パドル', 'ギア', 'ピックルボール用のラケット。テニスラケットより小さくストリングがない。カーボンファイバー、フィバーグラス、ポリマーハニカムコアなどが使用される。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_core', 'Core (Paddle Core)', 'コア（パドルの芯材）', 'ギア', 'パドル内部のハニカム構造の素材。ポリマー（ポリプロピレン）が主流。コアの厚さ（13mm/14mm/16mm）がパワーとコントロールのバランスを決める。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_face', 'Face (Paddle Face)', 'フェイス（パドル打面素材）', 'ギア', 'パドルの打球面の素材。カーボンファイバー（T700, Toray等）、ファイバーグラス、ケブラーなどがあり、スピン性能やタッチに影響する。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_sweet_spot', 'Sweet Spot', 'スウィートスポット', 'ギア', 'パドルで最も効率よくボールを打てる中心部分。エロンゲーテッド（長尺）パドルはスウィートスポットが小さくなる傾向がある。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_thermoformed', 'Thermoformed / Unibody', 'サーモフォーム / ユニボディ', 'ギア', 'パドル製造技術の一つ。フェイスとエッジを一体成型することでパワーと剛性を向上。2024年以降のトレンド技術。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_elongated', 'Elongated Paddle', 'エロンゲーテッド（長尺パドル）', 'ギア', '標準より縦に長いパドル形状（16.5インチ以上）。リーチが長くなりパワーも出やすいが、幅が狭くスウィートスポットが減る。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_lead_tape', 'Lead Tape', '鉛テープ（リードテープ）', 'ギア', 'パドルのエッジに貼って重量やバランスをカスタマイズする粘着テープ。パワーアップやスウィートスポット拡大に使用される。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_overgrip', 'Overgrip', 'オーバーグリップ', 'ギア', 'パドルのグリップの上に巻くテープ。汗を吸収し滑りを防ぐ。ドライタイプとウェットタイプがある。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_edge_guard', 'Edge Guard', 'エッジガード', 'ギア', 'パドル周辺部を保護するフレーム。摩耗を防ぐが、エッジレスデザイン（エッジガードなし）はスウィートスポットの拡大に寄与する。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_spin', 'Spin', 'スピン（回転）', 'テクニック', 'ボールに回転をかけること。トップスピン（順回転）、バックスピン（逆回転/スライス）、サイドスピンがある。パドル面のテクスチャが影響する。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_topspin', 'Topspin', 'トップスピン（順回転）', 'テクニック', 'ボールの上側を擦り上げてかける順回転。弧を描いて落下し、バウンド後に跳ね上がる。攻撃的なショットに有効。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_backspin', 'Backspin / Slice', 'バックスピン（逆回転）/ スライス', 'テクニック', 'ボールの下側を切るようにかける逆回転。バウンドが低く、相手のタイミングを外す。ドロップショットやディンクに有効。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_body_shot', 'Body Shot', 'ボディショット', '戦術', '意図的に相手の体に向けて打つショット。相手のパドル操作を困難にし、ミスを誘う戦術。特にバックハンド側の腰付近を狙う。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_transition_zone', 'Transition Zone / No Man''s Land', 'トランジションゾーン / ノーマンズランド', 'コート', 'ベースラインとキッチンラインの間のエリア。この位置に留まるのは不利なため、素早くキッチンラインまで前進することが求められる。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_baseline', 'Baseline', 'ベースライン', 'コート', 'コートの最も後方のライン。サーブはこのラインの後ろから打つ。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_centerline', 'Centerline', 'センターライン', 'コート', 'コートの中央を縦に分ける線。サービスコートの左右を区分する。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_dead_ball', 'Dead Ball', 'デッドボール', 'ルール', 'フォルト（違反）が発生しラリーが停止した状態のボール。プレイが中断される。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_fault', 'Fault', 'フォルト', 'ルール', 'ルール違反のこと。サーブミス、キッチン内ボレー、ボールのアウト、ネットタッチなどが該当する。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_let', 'Let (abolished)', 'レット（廃止）', 'ルール', '以前はサーブがネットに触れてサービスコートに入った場合やり直しだったが、2021年のルール改正でレットは廃止。ネットに触れても有効となった。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_foot_fault', 'Foot Fault', 'フットフォルト', 'ルール', 'サーブ時にベースラインを踏むか超える、またはボレー時にキッチンラインを踏むか入ることで発生するフォルト。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_skinny_singles', 'Skinny Singles', 'スキニーシングルス', 'ゲーム形式', 'コートの半面だけを使って行うシングルスの練習形式。実戦に近い状況でショットの正確性とフットワークを鍛えるのに最適。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_rally', 'Rally', 'ラリー', 'ゲーム', 'サーブから始まりフォルトで終わるまでの連続した打ち合い。ラリーが長く続くのがピックルボールの醍醐味。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_match_point', 'Match Point', 'マッチポイント', 'ゲーム', 'あと1点で試合に勝てる状態のこと。通常11点先取で10点以上（2点差が必要）の場面。');
INSERT INTO local_community (category, description, articles) VALUES ('ローカル・コート情報 (Local & Community)', '日本国内でピックルボールをプレイできる場所の探し方や、自分たちでコートを作る（ラインを引く）方法などをまとめた記事データです。', '[{"id":"art_local_find_courts","title":"日本全国のピックルボールコートの探し方：おすすめサイト＆アプリまとめ","target_audience":"全員","content_summary":"日本国内でもピックルボールコートは急増中（全国500箇所以上）です。「Pickleball Japan Hub」や「ピックルボールナビ」、「テニスベア」などの検索サイトを利用すれば、地域別や屋内・屋外、レンタル品の有無で詳細な検索が可能です。USA Pickleball公式の「Place 2 Play」アプリなら世界中のコートも探せます。","related_website_url":"https://pickleballjapanhub.jp/","key_takeaways":["日本国内の検索は「Pickleball Japan Hub」や「テニスベア」が便利","海外も含めた検索なら「Place 2 Play」アプリを活用","テニスコートを転用している施設も多いため、事前にネットの高さを確認すると安心"]},{"id":"art_local_diy_court_lines","title":"体育館やテニスコートをピックルボール用に！DIYでラインを引く方法","target_audience":"コミュニティ主催者・施設管理者","content_summary":"ピックルボールのコートサイズ（13.4m × 6.1m）はバドミントンダブルスとほぼ同じです。既存の体育館やテニスコートに、剥がしやすいフロアテープ（ラインテープ）やペイントマーカー、あるいはL字・T字型のシリコン製簡易マーカーを使って、自分たちで一時的なコートスタジアムを作る具体的な方法を解説します。","related_youtube_url":"https://www.youtube.com/results?search_query=how+to+draw+pickleball+lines","key_takeaways":["バドミントンのコートサイズがベースになるので流用しやすい","体育館なら剥がしやすいフロア用ラインテープの活用を","置くだけですぐ構築できるシリコン製の「簡易コートマーカー」が手軽で便利"]}]');
