INSERT INTO drills (id, title, target_audience, content_summary, related_youtube_url, key_takeaways) VALUES ('art_strategy_third_shot_drop', 'ピックルボールの神髄「サードショット・ドロップ」を安定させる3つのコツ', '中級者', 'サードショットドロップは、サーバー側が不利な陣形をリセットし、ネット前へ前進するための最も重要なショットです。パドルを優しく握り、下から上へ押し上げるように打ち、ボールの軌道の頂点が自陣からネットの間にくるようにコントロールするのがポイント。相手のボールが最高点から落ちてくるタイミングを狙うと打ちやすくなります。', 'https://www.youtube.com/results?search_query=サードショットドロップ+コツ+ピックルボール', '["パドルは強く握らず、ボールをキャッチして運ぶイメージ","ボールの軌道の頂点を自陣側に作り、相手のキッチンに落とす","打ったらすぐにネット（キッチンライン）へ前進する"]');
INSERT INTO drills (id, title, target_audience, content_summary, related_youtube_url, key_takeaways) VALUES ('art_drill_wall_dink', '1日15分で劇的変化！自宅でできる「ディンク壁打ちドリル」完全ガイド', '初心者〜上級者', 'ディンクの精度を上げるには反復練習が不可欠です。室内用の静かなボールを使えば、自宅の壁でも練習可能です。フォア・バックの交互打ち、スピードアップからのリセットなど、壁打ち（Wall Drill）は1試合よりもはるかに多くの球数を打てるため、最強の自主練方法となります。', 'https://www.youtube.com/results?search_query=pickleball+wall+drill', '["壁打ち15分は、1試合分のショット数に匹敵する","ネットの少し上を狙って、パドル面を一定に保つ練習をする","柔らかい練習用ボールを使えば自宅でも実施可能"]');
INSERT INTO drills (id, title, target_audience, content_summary, related_youtube_url, key_takeaways) VALUES ('art_strategy_stacking', 'ダブルスの勝率を上げる陣形「スタッキング」の基本とローテーション', '中級者〜上級者', 'スタッキングとは、ダブルスでペアの得意なサイド（例：フォアハンドが強い選手を中央に配置する）を維持し続けるための陣形戦術です。特に右利きと左利きのペアで絶大な威力を発揮します。サーブやリターンの後に配置を入れ替えるため、最初はスコア（偶数・奇数）に応じた立ち位置のルール「アンワインド・ザ・スタック」を覚える必要があります。', 'https://www.youtube.com/results?search_query=pickleball+stacking+strategy', '["スタッキングは得意なショット（フォア）を常に中央に集めるための戦術","右利き×左利きペアでは必須の陣形","ペア間の明確なサイン（ハンドシグナル等）とコミュニケーションが鍵"]');
