INSERT INTO injury_preventions (target_condition, cause, prevention_gears, stretches) VALUES ('Pickleball Elbow (テニス肘 / 上腕骨外側上顆炎)', 'バックハンドの使いすぎや、パドルの芯を外した際の衝撃が肘に蓄積することで発生する炎症。', 'ショックアブソーバー（振動吸収材）、エルボーバンド（サポーター）、より厚いコア（16mm等）のパドルへの変更', '手首を曲げ伸ばしする前腕のストレッチ。壁を使った肩周りのストレッチ。');
INSERT INTO injury_preventions (target_condition, cause, prevention_gears, stretches) VALUES ('Eye Injuries (眼球へのボール直撃)', 'ネット前での超至近距離のファイヤーファイト（打ち合い）時に、予期せぬ弾道のボールが目に直撃する事故。', 'スポーツ用アイウェア（保護メガネ）、クリアレンズのサングラス。ポリカーボネート製の割れないレンズが推奨される。', '該当なし（保護具の着用が唯一の予防策）');
INSERT INTO injury_preventions (target_condition, cause, prevention_gears, stretches) VALUES ('Achilles Tendonitis / Ankle Sprains (アキレス腱炎 / 足首の捻挫)', '前後左右への急激な方向転換、特にキッチンラインへのダッシュとその激しいストップ動作。', 'ピックルボールまたはテニス専用の「横方向の動きに強い」コートシューズ。※ランニングシューズは捻挫のリスクが高いため絶対に使用しないこと。', 'アキレス腱伸ばし、ふくらはぎのマッサージ、足首の回旋運動。');
INSERT INTO injury_preventions (id, injury_type, severity, prevention_methods, recovery_time, recommended_exercises, video_url, description) VALUES ('care_gen_1', 'アキレス腱炎', '軽度', '["ストレッチ","アイシング"]', '4〜6週間', '["ストレッチA: 前腕伸展","ストレッチB: 肩回し"]', 'https://www.youtube.com/results?search_query=pickleball+%E3%82%A2%E3%82%AD%E3%83%AC%E3%82%B9%E8%85%B1%E7%82%8E+予防', 'アキレス腱炎はピックルボールプレイヤーに多い怪我の一つです。適切な予防と対策で安全にプレーを続けましょう。');
