INSERT INTO coach_certifications (id, name, issuing_body, description, target_audience, website_url) VALUES ('cert_pci', 'PCI (Pickleball Coaching International)', 'Third Shot Sports / PCI', '世界で最も近代的な指導法と段階的なカリキュラムを提供するオンライン中心のコーチング認定プログラム。指導者としての「教え方（ティーチング・メソドロジー）」に重点を置いている。', '初心者〜中級者への指導を目指すコーチ', 'https://www.pickleballcoachinginternational.com/');
INSERT INTO coach_certifications (id, name, issuing_body, description, target_audience, website_url) VALUES ('cert_ppr', 'PPR (Professional Pickleball Registry)', 'Professional Tennis Registry (PTR) の姉妹組織', 'USAPAの公式コーチ認定パートナー。テニスコーチの経験を持つ人々がピックルボールの指導資格を取得するためのスタンダード。対面でのワークショップと実技試験がある。', 'プロのラケットスポーツコーチ、施設インストラクター', 'https://pprpickleball.org/');
