INSERT INTO coaches (id, name, specialty, achievements, teaching_style, target_level, media_url) VALUES ('coach-morgan-evans', 'Morgan Evans', '先進的なスピンコントロールとプロレベルの戦術指導', '["PPAツアー公認プロフェッショナルコーチ","Pickleball Coaching International (PCI) 創設メンバー","スピンサーブ（現在は制限）の発案者・戦術のパイオニア"]', 'バイオメカニクス（生体力学）に基づいたスイングの指導と、ゲームの流れを読む高度な戦術（パドルポジション、コート上のスペース管理）を論理的に解説するスタイル。トッププロから絶大な信頼を得ている。', '上級者・競技者向け', 'https://www.youtube.com/results?search_query=Morgan+Evans+Pickleball+Coach');
INSERT INTO coaches (id, name, specialty, achievements, teaching_style, target_level, media_url) VALUES ('coach-tyson-mcguffin', 'Tyson McGuffin', 'フットワークの強化とアグレッシブなプレイスタイル', '["PPAツアー 伝説的トッププロ選手（グランドスラム達成）","全米各地で開催される大規模キャンプ「TM Signature PB Camps」主宰","ピックルボール界で最も影響力のあるインフルエンサーの一人"]', '圧倒的な熱量とエネルギーで生徒を引っ張るスタイル。テニス出身者向けのフットワーク指導や、攻撃的なドライブの打ち方、そして何より「メンタルの強さ」を育てることに定評がある。', '中級者〜上級者向け', 'https://www.youtube.com/@TysonMcGuffin');
INSERT INTO coaches (id, name, specialty, achievements, teaching_style, target_level, media_url) VALUES ('coach-mark-renneson', 'Mark Renneson', '初心者から中級者へのステップアップ指導とコーチ育成', '["Third Shot Sports 創設者・CEO","Pickleball Coaching International (PCI) 代表","世界中で数千人のコーチを認定・育成した実績"]', '「なぜそのショットを打つのか？」という論理的な説明が非常に分かりやすい。初心者や中級者が陥りやすいミスを的確に指摘し、簡単なドリルを通じて短期間で上達させるマジックを持つ。', '初心者〜中級者および指導者向け', 'https://www.youtube.com/@ThirdShotSports');
