INSERT INTO activity_logs (id, user_id, facility_id, content, image_url, like_count, created_at) VALUES ('activity_log_001', 'user_mock_010', 'kpi_park_yokohama', 'KPI PARKで仲間と2時間プレー！ハードコートの弾みが最高で、良い練習になりました。やっぱり専用コートはテンション上がりますね！🏓', 'https://example-image-hosting.com/pickleball/log_kpi.jpg', 24, '2026-03-01T15:30:00Z');
INSERT INTO activity_logs (id, user_id, facility_id, content, image_url, like_count, created_at) VALUES ('activity_log_002', 'user_mock_015', 'tokyo_tower_pickleball', '東京タワーの下で初ピックルボール🗼！テニス経験があったので意外とすぐ打てるようになりました。今度はマイパドルを手に入れて来たいです！', 'https://example-image-hosting.com/pickleball/log_tokyotower.jpg', 58, '2026-03-02T19:45:00Z');
INSERT INTO activity_logs (id, user_id, facility_id, content, image_url, like_count, created_at) VALUES ('activity_log_003', 'user_mock_002', 'osaka_tsurumi_gym', 'LINKSの初心者講習会を開催。今日も新しく5名の方がピックルボールデビューしました！どんどん輪が広がっていて嬉しいです。', 'https://example-image-hosting.com/pickleball/log_links.jpg', 112, '2026-03-03T11:20:00Z');
INSERT INTO activity_logs (id, facility_id, content, like_count, created_at) VALUES ('log_001', 'facility_tokyotower', '今日は東京タワーの屋上でピックルボール！景色が最高すぎてテンション上がりました🏓✨ ナイターも涼しくて快適！', 24, '2026-03-01T18:30:00Z');
INSERT INTO activity_logs (id, facility_id, content, like_count, created_at) VALUES ('log_002', 'facility_viptop', '東陽町のVIPインドアで初打ち。冷房完備って素晴らしい…！夏場はここ一択かもしれないです。床のグリップも良好。', 15, '2026-02-28T14:15:00Z');
