INSERT INTO announcements (id, date, title, content, category) VALUES ('announce_001', '2026-03-01', 'サイトリニューアルのお知らせ', 'I LOVE PICKLEBALLのデータベースが大幅に復旧・強化されました！より正確なギア情報や地方のコート情報を追加しています。', 'システム');
INSERT INTO announcements (id, date, title, content, category) VALUES ('announce_002', '2026-03-03', '【イベント告知】東京タワーピックルボール体験会', '初心者向けのピックルボール体験会を東京タワー下のコートで開催します。手ぶらで参加可能です！詳細はイベントページをご確認ください。', 'イベント');
INSERT INTO announcements (id, date, title, content, category) VALUES ('announce_003', '2026-03-05', '新進気鋭のパドルブランド「FRIDAY」の取り扱い開始', '安価で高性能なスターターパドルとして人気の高い「FRIDAY ORIGINAL」のレビュー記事とEC連携を追加しました。初心者の方はぜひ「ギア選び」のページからチェックしてください。', 'ギア情報');
INSERT INTO announcements (id, title, category, content, published_at, is_important) VALUES ('announce_001', '「I LOVE PICKLEBALL」ベータ版リリースのお知らせ', 'system', '日本全国のピックルボール施設とギア情報を網羅した総合情報プラットフォームのベータ版が公開されました！皆様のフィードバックをお待ちしております。', '2026-03-01T10:00:00Z', TRUE);
INSERT INTO announcements (id, title, category, content, published_at, is_important) VALUES ('announce_002', '国内大会カレンダー（6月・全日本選手権）を更新しました', 'update', '大会（Events）ディレクトリに今年のJPA主催「全日本ピックルボール選手権大会」のエントリー要項とスケジュールが追加されました。', '2026-03-03T12:00:00Z', FALSE);
INSERT INTO announcements (id, date, title, content, category) VALUES ('announcement_gen_1', '2026-03-10', '新サークル登録開始 #1', 'I LOVE PICKLEBALLをご利用いただきありがとうございます。最新の情報をお届けします。', 'メンテナンス');
