INSERT INTO communities (id, name, description, target_area, age_limit_min, age_limit_max, target_level, beginner_friendly, play_style, activity_frequency, schedule_text, external_url, location_text, owner_user_id, created_at) VALUES ('community_tokyo_shinjuku', '新宿ピックルボール', '2024年11月に活動を開始した初心者歓迎のサークルです。ラケットスポーツ経験者を中心に、新宿区内のスポーツ施設を貸し切って活動しています。', '東京都新宿区', 18, 60, '初心者〜中級者', TRUE, 'エンジョイ・混合', '週1回以上', '週末を中心に不定期（LINE公式アカウントで調整）', 'https://www.tennisbear.net/circle/84045/info', '新宿区内のスポーツ施設', 'user_mock_001', '2024-11-01T00:00:00Z');
INSERT INTO communities (id, name, description, target_area, age_limit_min, age_limit_max, target_level, beginner_friendly, play_style, activity_frequency, schedule_text, external_url, location_text, owner_user_id, created_at) VALUES ('community_osaka_links', 'PickleBall LINKS', '2025年5月に設立された大阪市鶴見区周辺で活動するサークルです。ピックルボールコーディネーター資格を持つ指導者がおり、初心者講習会も開催しています。', '大阪府大阪市鶴見区', 10, 60, '未経験〜中級者', TRUE, 'エンジョイ・レッスンあり', '月3〜5回', '平日夜と土曜日', 'https://lit.link/pickleballlinks', '大阪市鶴見区周辺の体育館', 'user_mock_002', '2025-05-01T00:00:00Z');
INSERT INTO communities (id, name, description, target_area, age_limit_min, age_limit_max, target_level, beginner_friendly, play_style, activity_frequency, schedule_text, external_url, location_text, owner_user_id, created_at) VALUES ('community_fukuoka_infinity', 'INFINITY インフィニティー Fukuoka', '福岡で活動するピックルボールサークルです。入会費・年会費なしで、オープンチャットから気軽に参加申し込みが可能です。', '福岡県福岡市', 18, 99, '初心者〜中級者', TRUE, 'エンジョイ', '不定期', 'サークルイベントごとに告知', 'https://tunagate.com/circle/89758', '福岡市内のコート', 'user_mock_003', '2023-04-01T00:00:00Z');
INSERT INTO communities (id, name, description, target_area, target_level, beginner_friendly, play_style, activity_frequency) VALUES ('community_001', '東京ウィークエンド・ピックルボーラーズ', '東京都内（主に有明、東陽町など）で週末に集まってエンジョイプレーを楽しむ社会人サークルです。全くの初心者も歓迎！', '東京都', '初心者〜中級者 (DUPR 2.0 - 3.5)', TRUE, 'エンジョイ主体', '週1〜2回（土日祝）');
INSERT INTO communities (id, name, description, target_area, target_level, beginner_friendly, play_style, activity_frequency) VALUES ('community_002', '関西コンペティティブ PBクラブ', 'JPA公式大会や草大会での上位入賞を目指す、競技志向の強いプレイヤー向けのクラブ。定期的なドリル練習と試合形式をメインに行います。', '大阪府・兵庫県', '中級者〜上級者 (DUPR 4.0+)', FALSE, '競技志向', '週2回（水曜夜、日曜午前）');
