INSERT INTO drills (id, title, target_level, skill_focus, youtube_url, description) VALUES ('drill_third_shot_drop_101', '初心者向け：サードショット・ドロップの基本と成功率をあげるコツ', '初心者向け', 'サードショットドロップ', 'https://www.youtube.com/watch?v=F1ontvvINWQ', 'ピックルボールで最も重要な「サードショット・ドロップ」を安定させるための初心者向け練習メニュー。カゴ出しからの打ち込みと、ノーバウンドでのキャッチ練習を解説しています。');
INSERT INTO drills (id, title, target_level, skill_focus, youtube_url, description) VALUES ('drill_dink_patience', 'ディンクラリーで我慢する！忍耐力を鍛える壁打ち＆クロスドリル', '中級者向け', 'ディンク', 'https://www.youtube.com/watch?v=W14EVVU3Es7E', 'キッチン（ノンボレーゾーン）での攻防で、甘い球を上げずにしぶとくクロスに返し続けるためのドリル。焦って強打してしまうミスを減らすことに特化しています。');
INSERT INTO drills (id, title, target_level, skill_focus, youtube_url, description) VALUES ('drill_fast_hands_battle', '前衛でのファイヤーファイト（高速ボレー戦）を制する特訓', '上級者向け', 'ボレー戦', 'https://www.youtube.com/watch?v=kEf3HmYWOyg', 'プロレベルの試合で頻出する、至近距離でのボレーの打ち合い（ハンドバトル）に勝つための反射神経・ブロック練習。ラケットを胸の前に構えた状態からのコンパクトなスウィングを身につけます。');
INSERT INTO drills (id, title, target_level, skill_focus, youtube_url, description) VALUES ('drill_transition_zone', 'トランジションゾーン（ノーマンズランド）の歩き方とリセット', '中級者向け', 'トランジション', 'https://www.youtube.com/watch?v=Y3Qz95GrQqiH', 'ベースラインからキッチンへ前進する途中の「デッドゾーン」にボールを落とされた時の対処法。ブロックアウトしてリセット（緩い球で返球）し、安全に前衛につくためのステップワーク解説。');
INSERT INTO drills (id, title, target_level, skill_focus, description, youtube_search_url) VALUES ('drill_beginner_01', '初心者のためのディンク練習（Dink Drill）', '初心者向け', 'ディンク（キッチンでのコントロール）', 'ノンボレーゾーン（キッチン）での基本的な打ち合い。パドルの面を下から上へ向け、ボールを優しく持ち上げる感覚を養うドリル。手首を使わず、肩を支点にスイングすることが重要。', 'https://www.youtube.com/results?search_query=pickleball+dink+drill+beginner');
INSERT INTO drills (id, title, target_level, skill_focus, description, youtube_search_url) VALUES ('drill_beginner_02', '正しいサーブとリターンの基本', '初心者向け', 'サーブ＆リターン', 'ツーバウンスルールを確実に守るため、深くコントロールされたサーブと、ベースライン深くへ返すリターンを反復練習する。', 'https://www.youtube.com/results?search_query=pickleball+serve+and+return+drill');
INSERT INTO drills (id, title, target_level, skill_focus, description, youtube_search_url) VALUES ('drill_intermediate_01', 'サードショットドロップ（Third Shot Drop）マスター', '中級者向け', 'サードショットドロップ', '中級者への最大の壁であるサードショットドロップの練習。ベースラインから、相手のキッチン内にボールを落とし、前進する時間を作るコントロールを身につける。', 'https://www.youtube.com/results?search_query=pickleball+third+shot+drop+drill');
INSERT INTO drills (id, title, target_level, skill_focus, description, youtube_search_url) VALUES ('drill_intermediate_02', 'トランジションゾーン（ノーマンズランド）の攻略', '中級者向け', 'トランジション、リセット', 'ベースラインからキッチンへ向かう途中の「トランジションゾーン（ノーマンズランド）」でボールを足元に打たれた際、柔らかくブロックして相手のキッチンに落とす（リセットする）ドリル。', 'https://www.youtube.com/results?search_query=pickleball+transition+zone+reset+drill');
INSERT INTO drills (id, title, target_level, skill_focus, youtube_url, description) VALUES ('drill_gen_1', '【中上級者向け】 ディンク向上ドリル 1', '中上級者向け', 'ディンク', 'https://www.youtube.com/results?search_query=pickleball+%E3%83%87%E3%82%A3%E3%83%B3%E3%82%AF+drill', 'ディンクのスキルを向上させるための中上級者向けの決定版ドリル。1日10分の反復練習で安定感を劇的にアップさせます。');
INSERT INTO drills (id, title, target_level, skill_focus, youtube_url, description) VALUES ('drill_gen_2', '【中級者向け】 リターン向上ドリル 2', '中級者向け', 'リターン', 'https://www.youtube.com/results?search_query=pickleball+%E3%83%AA%E3%82%BF%E3%83%BC%E3%83%B3+drill', 'リターンのスキルを向上させるための中級者向けの決定版ドリル。1日10分の反復練習で安定感を劇的にアップさせます。');
INSERT INTO drills (id, title, target_level, skill_focus, youtube_url, description) VALUES ('drill_gen_3', '【初心者向け】 サーブ向上ドリル 3', '初心者向け', 'サーブ', 'https://www.youtube.com/results?search_query=pickleball+%E3%82%B5%E3%83%BC%E3%83%96+drill', 'サーブのスキルを向上させるための初心者向けの決定版ドリル。1日10分の反復練習で安定感を劇的にアップさせます。');
