INSERT INTO drills (id, title, target_level, skill_focus, youtube_url, description) VALUES ('drill_gen_5', '【初中級者向け】 ボレー向上ドリル 5', '初中級者向け', 'ボレー', 'https://www.youtube.com/results?search_query=pickleball+%E3%83%9C%E3%83%AC%E3%83%BC+drill', 'ボレーのスキルを向上させるための初中級者向けの決定版ドリル。1日10分の反復練習で安定感を劇的にアップさせます。');
