INSERT INTO tournaments_and_events (id, title, category, location, description, held_month, status) VALUES ('tournament_usap_national', 'Biofreeze USA Pickleball National Championships', '国際大会（メジャー）', 'Dallas, Texas, USA', '世界最高峰の権威を持つ全米選手権。プロ層だけでなくあらゆる年代・レベルのアマチュアが参加する、世界最大規模のピックルボールの祭典。', '11月', 'annual');
INSERT INTO tournaments_and_events (id, title, category, location, description, held_month, status) VALUES ('tournament_us_open', 'Minto US Open Pickleball Championships', '国際大会', 'Naples, Florida, USA', 'フロリダ州ネープルズで開催される世界有数のメガトーナメント。「ピックルボール界で最も熱狂的な1週間」とも称される。', '4月', 'annual');
INSERT INTO tournaments_and_events (id, title, category, location, description, held_month, status) VALUES ('tournament_jpa_japan_national', 'JPA ピックルボール日本一決定戦', '国内メジャー（JPA主催）', 'Ariake Tennis Forest Park (過去実績: 有明テニスの森 等)', '日本ピックルボール協会(JPA)が主催する、名実ともに日本最高峰の公式大会。シングルス、ダブルス、ミックスの各カテゴリーで世代別のチャンピオンを決定する。', '12月', 'annual');
INSERT INTO tournaments_and_events (id, title, category, location, description, held_month, status) VALUES ('tournament_jpa_all_japan', '全日本ピックルボール選手権大会', '国内メジャー（JPA主催）', 'Saorina, Mie (過去実績: サオリーナ 等)', '日本国内のプレイヤーが腕を競い合う、国内最大規模の選手権大会。', '6月', 'annual');
