INSERT INTO facility_comments (id, facility_id, user_id, content, created_at) VALUES ('f_comment_001', 'kpi_park_yokohama', 'user_mock_005', '日本最大級というだけあって、ハードコートのクオリティは文句なし。ただ、週末は予約が激戦なので早めに動く必要があります。更衣室も綺麗でした。', '2026-02-15T18:00:00Z');
INSERT INTO facility_comments (id, facility_id, user_id, content, created_at) VALUES ('f_comment_002', 'tokyo_tower_pickleball', 'user_mock_012', '東京タワーを見上げながらのプレーは最高に映えます！初心者向けの体験会でラケットも貸してもらえたので、手ぶらで行けました。また行きたいです。', '2026-03-01T20:30:00Z');
INSERT INTO facility_comments (id, facility_id, user_id, content, created_at) VALUES ('f_comment_003', 'osaka_tsurumi_gym', 'user_mock_009', '体育館なので天候に左右されないのが良いですね。ただ、バドミントンのラインが多くて最初は戸惑いました。サークルの活動場所としては最適です。', '2026-02-28T10:15:00Z');
INSERT INTO facility_comments (id, facility_id, user_id, rating, comment, visit_date, created_at) VALUES ('comment_gen_1', 'facility_gen_kanto_2', 'user_6', 4, '料金が手頃で定期的に通えます。コーチもいて教えてもらえます。', '2026-02-03', '2026-03-03T13:00:00Z');
INSERT INTO facility_comments (id, facility_id, user_id, rating, comment, visit_date, created_at) VALUES ('comment_gen_2', 'facility_gen_kanto_12', 'user_22', 4, 'コートの状態が非常に良く、快適にプレーできました。スタッフも親切です。', '2026-02-08', '2026-03-03T14:00:00Z');
INSERT INTO facility_comments (id, facility_id, user_id, rating, comment, visit_date, created_at) VALUES ('comment_gen_3', 'facility_gen_kansai_15', 'user_41', 3, 'レンタルパドルがあるので手ぶらで行けます。更衣室もきれいでした。', '2026-01-05', '2026-03-01T09:00:00Z');
INSERT INTO facility_comments (id, facility_id, user_id, rating, comment, visit_date, created_at) VALUES ('comment_gen_4', 'facility_gen_kansai_8', 'user_37', 3, '初心者でも気軽に参加できる雰囲気が良かったです。また利用したいです。', '2026-02-26', '2026-03-01T08:00:00Z');
INSERT INTO facility_comments (id, facility_id, user_id, rating, comment, visit_date, created_at) VALUES ('comment_gen_5', 'facility_gen_chubu_29', 'user_21', 5, '混雑していて待ち時間が長かった。平日の方が空いていておすすめ。', '2026-02-10', '2026-03-03T17:00:00Z');
