INSERT INTO gears_apparel (id, brand_name, product_name, category, target_gender, description) VALUES ('gear_apparel_001', 'FILA', 'Heritage Pickleball Polo', 'アパレル', 'men', '吸水速乾性に優れたポリエステル素材を使用。クラシックなデザインで、プロ大会でも多くのプレイヤーに愛用されているポロシャツ。');
INSERT INTO gears_apparel (id, brand_name, product_name, category, target_gender, description) VALUES ('gear_apparel_002', 'Skechers', 'Viper Court Skort', 'アパレル', 'women', 'ピックルボールの激しい動きに対応するインナースパッツ付きのスコート。ボールポケット付きで実用性抜群。');
INSERT INTO gears_apparel (id, brand_name, product_name, category, target_gender, description) VALUES ('gear_bag_001', 'JOOLA', 'Tour Elite Pickleball Bag', 'バッグ', 'unisex', 'パドルが最低4本、シューズ（専用コンパートメント）、着替え、水筒など、トーナメントに必要なすべてを収納できる大容量プロ仕様バッグ。熱からパドルを守る断熱ポケット(サーマルガード)を搭載。');
