INSERT INTO gears_balls (category, description, items) VALUES ('Pickleball Balls', 'ピックルボールの公式試合や練習で使用される代表的なボールのデータです。屋内用（インドア）と屋外用（アウトドア）で穴の数や硬さが異なります。', '[{"id":"franklin-x-40","brand":"Franklin","model":"X-40","type":"Outdoor","holes":40,"weight_grams":26,"features":["USAPA公認球","多くのメジャートーナメント（US Openなど）での公式球","耐久性と飛行の安定性に優れる","やや柔らかめの打感"],"best_for":"屋外コートでの標準的なプレイ、初心者からプロまで","amazon_url":"https://www.amazon.co.jp/s?k=Franklin+X-40+Pickleball","rakuten_url":"https://search.rakuten.co.jp/search/mall/Franklin+X-40+Pickleball/","yahoo_url":"https://shopping.yahoo.co.jp/search?p=Franklin+X-40+Pickleball"},{"id":"dura-fast-40","brand":"Dura","model":"Fast 40","type":"Outdoor","holes":40,"weight_grams":26,"features":["USAPA公認球","PPAツアーなどのプロトーナメントで頻繁に使用される","硬めの素材でスピードが出やすい","X-40に比べると寒冷地での耐久性にやや難がある（割れやすい）"],"best_for":"スピードと攻撃的なプレイを好む上級者・プロ","amazon_url":"https://www.amazon.co.jp/s?k=Dura+Fast+40+Pickleball","rakuten_url":"https://search.rakuten.co.jp/search/mall/Dura+Fast+40+Pickleball/","yahoo_url":"https://shopping.yahoo.co.jp/search?p=Dura+Fast+40+Pickleball"},{"id":"vulcan-v520","brand":"Vulcan","model":"V520","type":"Indoor","holes":26,"weight_grams":26,"features":["USAPA公認球","インドア環境（体育館の床など）に最適化","スキッド（滑り）を軽減する表面加工","穴の数が少なく、風の影響を受けない屋内での正確なバウンスを実現"],"best_for":"屋内の木製・合成床コートでのプレイ","amazon_url":"https://www.amazon.co.jp/s?k=Vulcan+V520+Pickleball","rakuten_url":"https://search.rakuten.co.jp/search/mall/Vulcan+V520+Pickleball/","yahoo_url":"https://shopping.yahoo.co.jp/search?p=Vulcan+V520+Pickleball"}]');
INSERT INTO gears_accessories (id, category, name, description, usage_tips, price_range) VALUES ('item_lead_tape', 'カスタマイズ用品', 'Pickleball Lead Tape (鉛テープ)', 'パドルのエッジに貼ることで重量を加え、スウィートスポットを拡大し、パワーと安定性を向上させる競技者必須のアイテム。', 'スウィートスポットを横に広げたい場合は3時と9時の位置に、ヘッドを重くしてパワーを出したい場合は12時の位置に貼るのが一般的。', '1,000円〜2,000円');
INSERT INTO gears_accessories (id, category, name, description, usage_tips, price_range) VALUES ('item_overgrip', 'グリップ関連', 'Tourna Grip (トーナグリップ) / 各種オーバーグリップ', '汗を吸収し、パドルが滑るのを防ぐために元グリップの上に巻くテープ。ドライタイプとウェットタイプがある。', '夏場や手汗を多くかく人は、テニスでも有名な『トーナグリップ（ドライ）』が推奨される。頻繁に巻き替えることで最高のパフォーマンスを維持できる。', '3本入り 1,200円前後');
INSERT INTO gears_accessories (id, category, name, description, usage_tips, price_range) VALUES ('item_edge_guard_tape', '保護用品', 'Edge Guard Tape (エッジガードテープ)', '低いボールを拾う際など、コートの床や地面にパドルの縁が擦れて削れるのを防ぐ保護テープ。', '高価なパドル（カーボンファイバー製など）を長持ちさせるために、購入直後に貼るプロが多い。デザイン性のあるものを選ぶとカスタマイズにもなる。', '1,500円〜2,500円');
