INSERT INTO pro_players (id, name, specialty, paddle_sponsor, achievements, playing_style, dupr_rating, youtube_search_url, official_website_url) VALUES ('dayne-gingrich', 'Dayne Gingrich', 'メンタリティと圧倒的なコートカバーリング', 'Engage', '["シニアプロ部門 男子ダブルス ランキング常連","PPAツアー シニアプロ部門タイトル多数獲得","著書『The Pickleball Mindset』の著者"]', '驚異的な身体能力と、相手にプレッシャーをかけ続けるアグレッシブなプレー。圧倒的なメンタルの強さで知られ、試合の流れを引き寄せる。', '5.5+', 'https://www.youtube.com/results?search_query=Dayne+Gingrich+pickleball', 'https://daynegingrich.com/');
INSERT INTO pro_players (id, name, specialty, paddle_sponsor, achievements, playing_style, dupr_rating, youtube_search_url, instagram_url) VALUES ('scott-moore', 'Scott Moore', '正確無比なドロップショットと戦略的な配球', 'Paddletek', '["USAPA ナショナルチャンピオンシップ シニアプロ部門タイトル多数（史上最多クラス）","トリプルクラウン（シングルス、男子ダブルス、混合ダブルス制覇）達成","Pickleball Hall of Fame（殿堂入り）"]', '「ピックルボール界のレジェンド」と称される。力に頼らず、完璧なコースへの配球とディンクラリーで相手のミスを誘う精密なプレースタイル。', '5.5+', 'https://www.youtube.com/results?search_query=Scott+Moore+pickleball', 'https://www.instagram.com/scottmoorepickleball/');
INSERT INTO pro_players (id, name, specialty, paddle_sponsor, achievements, playing_style, dupr_rating, youtube_search_url, npl_team_affiliation) VALUES ('beth-bellamy', 'Beth Bellamy', 'コート全体を使った多彩なショット', 'Joola', '["APPツアー シニアプロ部門 女子ダブルス・混合ダブルス ランキング1位に君臨","年間多数の金メダル獲得","全米オープン シニアプロ部門制覇"]', '元プロテニス選手の経験を活かした、強力なグラウンドストロークと鋭いボレー。コート全体を見渡す戦術眼と、プレッシャーに強いメンタルを持つ。', '5.0+', 'https://www.youtube.com/results?search_query=Beth+Bellamy+pickleball', 'OKC Punishers');
