INSERT INTO advanced_shots (id, name, difficulty, description, when_to_use, how_to_execute, drills, risk, youtube_tutorial_url) VALUES ('erne', 'アーネ（Erne）', '上級', 'ノンボレーゾーン（キッチン）の外側、コートの横幅を飛び越えて空中でボレーを打つ、または着地してから打つ攻撃的なショット。キッチンのルール（空中で打つ場合は着地してはいけない）を回避してネット近くでスマッシュを打つことができる。', '相手がサイドラインぎりぎりの甘いディンクやドロップを打ってきた時。相手の予測を裏切り、素早く得点したい時。', '["1. 相手のショットが自陣のサイドライン側に甘く入ると予測する。","2. キッチンのラインを踏まないように、サイドラインの外側へジャンプ（または素早く移動）する。","3. ボールがネットを越えた直後、高い打点でボレー（またはスマッシュ）を打ち込む。","4. 打った後も、キッチン内に着地したり、体が触れたりしないようバランスを保つ。"]', '["パートナーにサイドライン際にボールを出してもらい、タイミングを合わせてジャンプ・スイングする練習。","足元（ライン）を見ずに、ボールに集中しながら跳ぶ感覚を養うシャドードリル。"]', 'タイミングを逃すとポジションを失い、逆サイドを抜かれる危険がある。キッチンフォルトに注意。', 'https://www.youtube.com/results?search_query=Erne+pickleball+tutorial');
INSERT INTO advanced_shots (id, name, difficulty, description, when_to_use, how_to_execute, drills, risk, youtube_tutorial_url) VALUES ('around-the-post-atp', 'ATP（Around The Post）', '上級', 'ネットの上を通すのではなく、ネットポスト（支柱）の外側、コートの横を通って相手コートに入れるショット。ピックルボール特有のルールで認められている非常にエキサイティングなプレー。', '相手の強烈なアングルショット（角度のついたショット）によって、自分がサイドラインの外側深くまで追い出された時。ボールが極端に低く、ネットを越すのが難しい時。', '["1. 相手のアングルショットを追いかけ、サイドラインの外側へ走る。","2. ボールを十分低く（地面すれすれまで）引きつける。","3. 下からすくい上げるのではなく、ボールの横面を捉えてストレート（ポストの外側）へ打ち抜く。","4. 打球がネットシステムの『外側』を通り、相手コート内に着弾するようにコントロールする。"]', '["パートナーにネットポストの外側へ向けて手でボールを転がしてもらい、それを拾って打つ練習。","ポストの外側から打つ時の独特の軌道とラケット面の角度を体に覚えさせる。"]', 'ボールを引きつけすぎると打てなくなる。また、打った後に勢い余って相手コートに入ってしまうとフォルトになる。', 'https://www.youtube.com/results?search_query=ATP+pickleball+tutorial');
INSERT INTO advanced_shots (id, name, difficulty, description, when_to_use, how_to_execute, drills, risk, youtube_tutorial_url) VALUES ('third-shot-drop-topspin', 'サードショット・ドロップ（トップスピン）', '中・上級', 'ベースラインからの第3打（サードショット）を、相手のキッチンにふわりと落とす「ドロップショット」に、強いトップスピン（順回転）をかけたもの。バウンド後に低く滑るように弾むため、相手の攻撃を防ぎやすい。', 'リターンを待ってベースラインにいる時。ネットプレー（キッチンライン）へ前進するための時間を作りたい時。', '["1. ボールを下からすくい上げるのではなく、ボールの後ろから前下へ下から上へこすり上げるようにスイングする。","2. ラケット面を少し伏せ気味にし、インパクトの瞬間に手首を使って回転をかける（ブラッシング）。","3. ネットのやや上を狙い、相手のキッチン内に落とす軌道をイメージする。","4. 打った直後に、ボールの軌道の下へ潜り込むようにネットへ前進を開始する。"]', '["ベースラインから連続してドロップショットを打ち、パートナーにキッチンラインでそれを処理（ディンクやボレー）してもらう反復練習。","的（ターゲット）をキッチン内に置き、そこにトップスピンをかけて落とす練習。"]', 'スピン量が足りないとボールが浮き、相手の餌食（スマッシュ）になる。ネットミスにも注意。', 'https://www.youtube.com/results?search_query=Third+shot+drop+topspin+pickleball+tutorial');
INSERT INTO advanced_shots (id, name, category, difficulty, description, drill_steps, tutorial_url) VALUES ('tactic_gen_1', 'アイ・フォーメーション パターン1', '攻撃技術', '上級', 'アイ・フォーメーションのバリエーションを解説。実践的な使い所と練習方法を詳しく解説します。', '["1. 基本姿勢の確認","2. コーチとの反復練習","3. 実践形式で試す"]', 'https://www.youtube.com/results?search_query=pickleball+%E3%82%A2%E3%82%A4%E3%83%BB%E3%83%95%E3%82%A9%E3%83%BC%E3%83%A1%E3%83%BC%E3%82%B7%E3%83%A7%E3%83%B3');
INSERT INTO advanced_shots (id, name, category, difficulty, description, drill_steps, tutorial_url) VALUES ('tactic_gen_2', 'クロスコートアタック パターン2', '攻撃技術', 'プロ級', 'クロスコートアタックのバリエーションを解説。実践的な使い所と練習方法を詳しく解説します。', '["1. 基本姿勢の確認","2. コーチとの反復練習","3. 実践形式で試す"]', 'https://www.youtube.com/results?search_query=pickleball+%E3%82%AF%E3%83%AD%E3%82%B9%E3%82%B3%E3%83%BC%E3%83%88%E3%82%A2%E3%82%BF%E3%83%83%E3%82%AF');
