INSERT INTO activity_logs (id, facility_id, content, like_count, created_at) VALUES ('log_001', 'facility_tokyotower', '今日は東京タワーの屋上でピックルボール！景色が最高すぎてテンション上がりました🏓✨ ナイターも涼しくて快適！', 24, '2026-03-01T18:30:00Z');
INSERT INTO activity_logs (id, facility_id, content, like_count, created_at) VALUES ('log_002', 'facility_viptop', '東陽町のVIPインドアで初打ち。冷房完備って素晴らしい…！夏場はここ一択かもしれないです。床のグリップも良好。', 15, '2026-02-28T14:15:00Z');
INSERT INTO announcements (id, title, category, content, published_at, is_important) VALUES ('announce_001', '「I LOVE PICKLEBALL」ベータ版リリースのお知らせ', 'system', '日本全国のピックルボール施設とギア情報を網羅した総合情報プラットフォームのベータ版が公開されました！皆様のフィードバックをお待ちしております。', '2026-03-01T10:00:00Z', TRUE);
INSERT INTO announcements (id, title, category, content, published_at, is_important) VALUES ('announce_002', '国内大会カレンダー（6月・全日本選手権）を更新しました', 'update', '大会（Events）ディレクトリに今年のJPA主催「全日本ピックルボール選手権大会」のエントリー要項とスケジュールが追加されました。', '2026-03-03T12:00:00Z', FALSE);
INSERT INTO gears_apparel (id, brand_name, product_name, category, target_gender, description) VALUES ('gear_apparel_001', 'FILA', 'Heritage Pickleball Polo', 'アパレル', 'men', '吸水速乾性に優れたポリエステル素材を使用。クラシックなデザインで、プロ大会でも多くのプレイヤーに愛用されているポロシャツ。');
INSERT INTO gears_apparel (id, brand_name, product_name, category, target_gender, description) VALUES ('gear_apparel_002', 'Skechers', 'Viper Court Skort', 'アパレル', 'women', 'ピックルボールの激しい動きに対応するインナースパッツ付きのスコート。ボールポケット付きで実用性抜群。');
INSERT INTO gears_apparel (id, brand_name, product_name, category, target_gender, description) VALUES ('gear_bag_001', 'JOOLA', 'Tour Elite Pickleball Bag', 'バッグ', 'unisex', 'パドルが最低4本、シューズ（専用コンパートメント）、着替え、水筒など、トーナメントに必要なすべてを収納できる大容量プロ仕様バッグ。熱からパドルを守る断熱ポケット(サーマルガード)を搭載。');
INSERT INTO awards (id, title, target_type, target_id, year, description) VALUES ('award_2025_best_paddle', '2025年 ユーザー投票 第1位「ベスト・パワーパドル」', 'gear', 'paddle_joola_perseus', 2025, '反発力とスピン性能で圧倒的な支持を集め、中〜上級者部門で堂々の1位を獲得。');
INSERT INTO awards (id, title, target_type, target_id, year, description) VALUES ('award_2025_best_facility', '2025年 みんなが選んだ「ベスト・インドアコート」', 'facility', 'facility_viptop', 2025, '冷暖房完備、アクセスの良さ、そして専用コートのクオリティが評価され初代ベストコートに選出。');
INSERT INTO drills (id, title, target_level, skill_focus, description, youtube_search_url) VALUES ('drill_beginner_01', '初心者のためのディンク練習（Dink Drill）', '初心者向け', 'ディンク（キッチンでのコントロール）', 'ノンボレーゾーン（キッチン）での基本的な打ち合い。パドルの面を下から上へ向け、ボールを優しく持ち上げる感覚を養うドリル。手首を使わず、肩を支点にスイングすることが重要。', 'https://www.youtube.com/results?search_query=pickleball+dink+drill+beginner');
INSERT INTO drills (id, title, target_level, skill_focus, description, youtube_search_url) VALUES ('drill_beginner_02', '正しいサーブとリターンの基本', '初心者向け', 'サーブ＆リターン', 'ツーバウンスルールを確実に守るため、深くコントロールされたサーブと、ベースライン深くへ返すリターンを反復練習する。', 'https://www.youtube.com/results?search_query=pickleball+serve+and+return+drill');
INSERT INTO drills (id, title, target_level, skill_focus, description, youtube_search_url) VALUES ('drill_intermediate_01', 'サードショットドロップ（Third Shot Drop）マスター', '中級者向け', 'サードショットドロップ', '中級者への最大の壁であるサードショットドロップの練習。ベースラインから、相手のキッチン内にボールを落とし、前進する時間を作るコントロールを身につける。', 'https://www.youtube.com/results?search_query=pickleball+third+shot+drop+drill');
INSERT INTO drills (id, title, target_level, skill_focus, description, youtube_search_url) VALUES ('drill_intermediate_02', 'トランジションゾーン（ノーマンズランド）の攻略', '中級者向け', 'トランジション、リセット', 'ベースラインからキッチンへ向かう途中の「トランジションゾーン（ノーマンズランド）」でボールを足元に打たれた際、柔らかくブロックして相手のキッチンに落とす（リセットする）ドリル。', 'https://www.youtube.com/results?search_query=pickleball+transition+zone+reset+drill');
INSERT INTO award_votes (id, award_id, user_id, voted_item_id, reason, created_at) VALUES ('vote_001', 'award_2025_power_paddle', 'user_demo_001', 'paddle_joola_perseus', '圧倒的なパワーで、これを持てば試合に勝てるから。', '2025-12-10T11:20:00Z');
