INSERT INTO community_threads (id, community_id, author_id, title, content, created_at) VALUES ('cthread_001', 'community_001', 'user_demo_001', '今週末の練習用ボール購入について', 'FranklinのX-40が減ってきたので、サークル費でダース買いしようと思います。異議ある方いますか？', '2026-03-01T12:00:00Z');
