INSERT INTO facility_comments (id, facility_id, user_id, content, created_at) VALUES ('fcomment_001', 'facility_viptop', 'user_demo_001', '冷房が効いていて夏場でも快適にプレーできました。ただ、週末は予約が取りづらいのが難点です。', '2026-03-01T14:30:00Z');
INSERT INTO facility_comments (id, facility_id, user_id, content, created_at) VALUES ('fcomment_002', 'facility_tokyotower', 'user_demo_002', '東京タワーを見上げながらのナイターは最高です！風の影響は受けやすいのでアウトドア用の重いボールが必須です。', '2026-03-02T21:00:00Z');
