INSERT INTO threads (id, category, title, content, status, responses) VALUES ('thread_001', 'rule_qa', 'NVZ（キッチン）ラインを踏んでボレーしてしまった場合', '初心者です。勢い余ってボレーを打った後にキッチンラインを踏んでしまったのですが、これはフォルトになりますか？', 'closed', '[{"user_id":"user_demo_001","content":"はい、フォルトになります。打つ瞬間だけでなく、打ったあとの惰性（モメンタム）でラインに触れたりキッチン内に入ったりした場合もフォルトです。"}]');
INSERT INTO threads (id, category, title, content, status, responses) VALUES ('thread_002', 'partner_search', '【土日】都内（有明・東陽町）で固定ペア募集！', 'DUPR3.5前後の30代男性です。ダブルスの固定ペアを探しています。まずは一度練習で合わせてみませんか？', 'open', '[]');
