INSERT INTO expert_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('review_001', 'paddle', 'paddle_joola_perseus', 'Ben Johns (JP Pro Tester)', 9.5, 'スイートスポットの広さと反発力は現行モデルで最強クラス。ただし14mmはかなり打感に硬さがあり、初心者が扱うにはパワーの制御が難しいため、中級者以上におすすめ。');
INSERT INTO expert_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('review_002', 'shoe', 'shoe_skechers_viper_court', 'Tyson McGuffin', 9, 'ピックルボール特有の横の動きに抜群の安定感がある。特にアウトソール部分のグリップ力が高く、ダッシュ＆ストップ時の安心感はピカイチ。幅広足の人にもフィットしやすい。');
INSERT INTO facility_community_media (id, target_type, target_id, media_type, url, description) VALUES ('media_fmedia_001', 'facility', 'facility_viptop', 'youtube', 'https://www.youtube.com/watch?v=dummy_viptop_intro', 'VIPインドア東陽町 施設紹介＆コートの広さ解説動画');
INSERT INTO facility_community_media (id, target_type, target_id, media_type, url, description) VALUES ('media_fmedia_002', 'facility', 'facility_tokyotower', 'instagram', 'https://www.instagram.com/p/dummy_tokyotower', '東京タワーを見上げる絶景ナイトピックルボールの様子');
INSERT INTO facility_community_media (id, target_type, target_id, media_type, url, description) VALUES ('media_cmedia_001', 'community', 'community_001', 'youtube', 'https://www.youtube.com/watch?v=dummy_community_practice', '東京ウィークエンド・ピックルボーラーズ 週末の練習風景（ディンクドリル）');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_kitchen', 'Kitchen / Non-Volley Zone (NVZ)', 'キッチン / ノンボレーゾーン', 'コート・ルール', 'ネットの両側7フィート（約2.13m）のエリア。このエリア内（ライン上を含む）では、ノーバウンドでの返球（ボレー）が禁止されている。ピックルボール最大の特徴。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_dink', 'Dink', 'ディンク', 'ショット', 'キッチンライン付近から、相手のキッチン内に優しく山なりに落とすコントロールショット。相手に攻撃させないための最も重要な戦術。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_third_shot_drop', 'Third Shot Drop', 'サードショット・ドロップ', '戦術・ショット', 'サーブ権を持つ側が打つ3球目のショットで、相手のキッチン内に落として前進する時間を作る高度な技術。');
INSERT INTO glossary (id, term_en, term_ja, category, description) VALUES ('term_reset', 'Reset', 'リセット', '戦術', '相手からの強い攻撃（ドライブ等）を柔らかくブロックし、再びキッチン内にボールを落としてラリーのペースを落ち着かせること。');
