INSERT INTO massive_salvage_communities_01 (id, name, target_area, target_level, beginner_friendly, play_style) VALUES ('com_049', '関東学生ピックルボール連盟', '関東広域', '大学生', 1, '競技志向');
INSERT INTO massive_salvage_communities_01 (id, name, target_area, target_level, beginner_friendly, play_style) VALUES ('com_050', '全国プロ育成プロジェクト', '全国', 'プロ志望', 0, '競技志向');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_01', 'ストレートディンクラリー', '初心者', 'ディンク', 'キッチンライン上で対面のパートナーとストレートにディンクを打ち続ける基本ドリル。手首を固定し、リラックスしたグリップで30球連続を目指す。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_02', 'クロスコートディンク', '初心者', 'ディンク', 'キッチンの対角線上にディンクを打ち合う。バックハンド側を意識的に練習することが重要。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_03', 'ディンクからのアタック判断', '中級者', 'ディンク', '相手のディンクが高く浮いたタイミングでスピードアップ（アタック）を選択する判断力を養うドリル。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_04', 'サーブ＆リターン基礎', '初心者', 'サーブ&リターン', 'コーンをサービスコートの四隅に置き、サーブの精度を高める。ディープサーブとショートサーブの打ち分けを練習する。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_05', 'ディープリターン練習', '初心者', 'サーブ&リターン', 'リターンを必ずサービスコート深くに返すことを目標とするドリル。相手がキッチンに来る時間を与えないためのディープリターンは最重要技術。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_06', 'サードショットドロップ ターゲット', '中級者', '戦術ショット', 'バックライン付近からキッチン内に山なりのボールを落とす練習。コーンをキッチン内に3個置き、その付近にバウンドさせることを目指す。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_07', 'サードショットドライブ', '中級者', '戦術ショット', 'サードショットとしてフラットなドライブで攻撃する練習。ドロップと見せかけてのドライブの切り替えを身につける。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_08', 'チェーングリル（打ち合いボレー）', '中級者', 'ボレー', 'キッチンライン上でスピードボレーを打ち合うスピードドリル。反射神経とパドルコントロールを鍛える。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_09', 'ブロックリセットドリル', '中級者', 'ボレー', '相手の強打に対して、パドルの面をオープンにして柔らかくキッチン内にリセットする技術を練習する。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_10', 'ロブ&スマッシュ', '初心者', 'ロブ', '一方がロブを上げ、もう一方がオーバーヘッドスマッシュで返球する交互練習。ロブの高さとスマッシュのタイミング両方を同時に学べる。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_11', 'ディフェンシブロブ', '上級者', 'ロブ', '苦しい体勢からあえてハイロブを打ち、体勢を立て直す時間を稼ぐための高度なディフェンステクニック。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_12', 'アーネ（Erne）シミュレーション', '上級者', '上級テクニック', 'キッチン横のサイドラインの外側に回り込み、NVZ違反なしにネット際のボールをボレーで叩く超上級テクニック。2人一組でタイミングのパターン練習をする。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_13', 'ATP（アラウンド・ザ・ポスト）練習', '上級者', '上級テクニック', 'ネットポストの外側を通してボールを返球する上級ショット。相手のワイドなディンクに対してこのショットが有効な場面を作り出すシチュエーションドリル。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_14', 'スタッキング陣形練習（ダブルス）', '中級者', 'ダブルス戦術', 'パートナーと横並びでスタートし、サーブ後にフォアハンドが強い側にポジション交換するスタッキングフォーメーションのドリル。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_15', 'シェイキングハンズ（鍔迫り合い）', '中級者', 'ボレー', 'ネット越しに2人で至近距離のボレー合戦をする超実戦的ドリル。パドルの出し方とターゲティングを鍛える。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_16', 'バックハンドロールディンク', '上級者', 'ディンク', 'バックハンド面に強いトップスピンをかけ、ネットすれすれを越えて相手の足元に沈めるディンク練習。手首のスナップが最重要。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_17', '2対1ラリー（ハンデ練習）', '中級者', '総合練習', 'コートの片側に2人、もう片側に1人を配置し、1人側がフルコートをカバーする高強度ラリー。スタミナとショット選択力を養う。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_18', 'スキニーシングルス', '初心者', '総合練習', 'コートの半面のみを使ったシングルス。狭いスペースで正確性を追求する最適な練習方法。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_19', 'トランジション(移行)ゾーンドリル', '中級者', 'フットワーク', 'バックラインからキッチンラインまでのスムーズな前進を反復するドリル。スプリットステップのタイミングを体に染み込ませる。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_20', 'シャドーフットワーク', '初心者', 'フットワーク', 'ボールなしでコート上を動き、正しいフットワークパターンを体に覚えさせるシャドー練習。横への素早いサイドステップが重要。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_21', 'プレッシャーサーブ', '上級者', 'サーブ&リターン', '連続でサービスエースを狙う高強度ドリル。ライン際・ボディ・フォア/バック側の3コースを使い分ける。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_22', 'パートナーチェンジラリー', '中級者', '総合練習', '4人以上で回しながらパートナーを定期的に入れ替えるラリー。対応力と多様なプレイスタイルへの適応力を養う。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_23', 'ボレーボレーカウント', '初心者', 'ボレー', 'ペアでボレーの連続打を行い、ミスなく何球続くか数えるシンプルかつ効果的なドリル。最高記録を更新していくモチベーション型。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_24', 'ディンク・トゥ・ドライブ切り替え', '上級者', '総合練習', 'ラリーをわざとスローペースのディンク戦で始め、合図とともに一気にトップスピンの効いたドライブ合戦に切り替える。実戦のペースチェンジを体で覚える。');
INSERT INTO drills (id, name, level, category, description) VALUES ('drill_25', '壁打ちディンク', '初心者', 'ディンク', '壁や練習用リバウンドボードに向かって一人でディンクの感覚を磨く自主練ドリル。タッチの繊細さを鍛える最も手軽な方法。');
