INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_01', 'paddle', 'pdl_selkirk_vanguard_pro', 'ベン・ジョンズ(プロ)', 9.5, 'Raw Carbon Fiberの打感が最高。スイートスポットが広く、スピンも申し分ない。トッププロが求める全てがある。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_02', 'paddle', 'pdl_joola_perseus_3', 'コリン・ジョンズ(プロ)', 9.2, 'プロパルジョンコアの反発力が次世代。コントロールとパワーの高次元な両立を実現。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_03', 'paddle', 'pdl_crbn_1x_16', 'ゼイン・ナバラティル(プロ)', 9, '16mmの安定感は抜群。ディンクの精度が激変する。スピン量もトップクラス。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_04', 'paddle', 'pdl_sixzero_dbd_16', '公認コーチ 佐藤', 8.8, 'エアロカーブ形状は独特だが、振り抜きと空気抵抗の低減効果は本物。初中級者の「次の一本」に最適。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_05', 'paddle', 'pdl_vatic_pro_prism_flash', '公認コーチ 佐藤', 9, 'この価格帯でこの性能は破壊的。1万5000円クラスの革命児。最もコスパの高いパドルとして自信を持っておすすめできる。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_06', 'paddle', 'pdl_gearbox_pro_power', '田中太郎(国内プロ)', 8.5, '全面カーボンSST構造は唯一無二。ハニカムなしのトランポリン感がなく、ダイレクトな打球感を求める人に。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_07', 'paddle', 'pdl_franklin_ben_johns', '公認コーチ 鈴木', 7.5, '1万7000円でこの品質は入門者にとって最高の選択肢。ただし上級者には物足りない。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_08', 'paddle', 'pdl_engage_pursuit_pro_ex', '山田花子(国内プロ)', 8.7, '摩擦加工のフェースは本当にスピンがかかる。特にバックハンドロールの精度が向上するのを実感。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_09', 'paddle', 'pdl_prokennex_blackace', '公認コーチ 鈴木', 8.3, 'キネティックテクノロジーはテニス肘に悩む方への福音。振動が本当に少ない。打球感は好みが分かれる。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_10', 'paddle', 'pdl_amazin_aces', '公認コーチ 鈴木', 5, '体験用・レンタル用としては十分。ただし競技への参入を少しでも考えるなら、すぐに買い替えるべき。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_11', 'shoe', 'shoe_05', '公認コーチ 佐藤', 9, '数少ないピックルボール「専用」シューズ。ガムソールの体育館での安定感は圧倒的。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_12', 'shoe', 'shoe_07', '田中太郎(国内プロ)', 8.8, 'Gelクッションの衝撃吸収力はシニアプレイヤーの膝にも優しい。コスパも文句なし。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_13', 'shoe', 'shoe_14', 'ベン・ジョンズ(プロ)', 9.2, '軽さとサポートの完璧な融合。Air Zoomのレスポンスは他の追随を許さない。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_14', 'shoe', 'shoe_01', '公認コーチ 鈴木', 8.5, 'K-Swissはピックルボール界のシューズNo.1。横方向のサポートが抜群。デザインもクリーン。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_15', 'ball', 'ball_01', '公認コーチ 佐藤', 9.5, 'アウトドアの公式球といえばこれ。飛距離と耐久性のバランスが最も良い。大会では必ずこのボール。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_16', 'ball', 'ball_04', 'ゼイン・ナバラティル(プロ)', 9, 'Dura Fast 40は打球感が最も硬く、飛びが鋭い。プロツアーの標準球。ただし割れやすいのが唯一の欠点。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_17', 'ball', 'ball_13', '公認コーチ 鈴木', 7, '騒音対策として非常に優れている。マンション住人への配慮が必要な練習場では必須アイテム。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_18', 'apparel', 'ap_01', '山田花子(国内プロ)', 9, 'Lululemonのプリーツスコートはデザイン・機能性ともにNo.1。ボールポケット付きで試合中も便利。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_19', 'apparel', 'ap_20', '公認コーチ 鈴木', 8.5, 'ユニクロのドライEXは驚くべきコスパ。初心者にまず最初に勧めるウェア。汗びっしょりになっても快適。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_20', 'accessory', 'acc_01', '田中太郎(国内プロ)', 9.2, 'ドライ系グリップのキング。汗を吸収して常にサラサラ。一度使うと他に戻れない。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_21', 'accessory', 'acc_11', '公認コーチ 佐藤', 9.5, '目のケガは取り返しがつかない。高いと感じるかもしれないが、Oakleyのプリズムレンズの視認性は別格。全プレイヤーに着用を推奨。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_22', 'accessory', 'acc_10', 'ゼイン・ナバラティル(プロ)', 7.5, '鉛テープは魔法のアイテム。パドルの打球感とパワーを自分好みにカスタマイズできる。位置で効果が全然違う。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_23', 'bag', 'bag_01', 'アンナ・リー・ウォーターズ(プロ)', 9, 'JOOLAのツアーバッグは収容力が圧倒的。パドル4本、シューズ、着替え、全部入る。遠征の味方。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_24', 'bag', 'bag_10', '山田花子(国内プロ)', 8, 'Nettieのコートトートは可愛い！保冷ポケットでドリンクも冷たいまま。女性プレイヤーに特におすすめ。');
INSERT INTO massive_salvage_reviews (id, item_type, item_id, expert_name, score, comment) VALUES ('rev_25', 'paddle', 'pdl_owl_quiet', '公認コーチ 鈴木', 7.8, '静音パドルの需要は確実に高まっている。住宅地近くのコートでは救世主。打感は少しこもるが許容範囲。');
