INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_01', 'PPA Tour - US Open Pickleball Championships', 'ネープルズ, フロリダ州, 米国', '国際メジャー', '毎年4月', '世界最大のピックルボール大会。フロリダ州ネープルズのイーストネープルズ・コミュニティパークで開催。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_02', 'PPA Tour - National Championships', 'ダラス, テキサス州, 米国', '国際メジャー', '毎年11月', 'PPA Tour年間チャンピオンを決定するシーズン最終戦。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_03', 'MLP (Major League Pickleball) Season', '全米各地(ローテーション)', 'プロリーグ', '年間5-6イベント', 'チーム対抗形式のプロリーグ。LeBron JamesやTom Bradyなど著名人がオーナーに名を連ねる。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_04', 'APP Tour - Atlantic Open', 'デルレイビーチ, フロリダ州, 米国', '国際プロツアー', '毎年2月', 'APP Tourの主要大会のひとつ。フロリダのビーチリゾート付近で開催される。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_05', 'Beer City Open', 'グランドラピッズ, ミシガン州, 米国', '国際プロツアー', '毎年7月', 'ビール醸造の街で開催される人気大会。アマチュアカテゴリも充実。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_06', 'Bainbridge Cup', 'ベインブリッジ島, ワシントン州, 米国', '国際招待', '毎年8月', 'ピックルボール発祥の地で開催されるエキシビション招待大会。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_07', 'JPA 全日本ピックルボール選手権大会', '東京都', '国内公式(JPA)', '毎年10月', '日本ピックルボール協会(JPA)主催の最高峰国内大会。全国各地の予選を勝ち抜いた選手が集結。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_08', 'JPA 東日本オープン', '東京都・神奈川県', '国内公式(JPA)', '毎年5月', '東日本エリアの代表選を兼ねた大規模オープン大会。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_09', 'JPA 西日本オープン', '大阪府', '国内公式(JPA)', '毎年6月', '西日本エリアの代表選を兼ねた大規模オープン大会。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_10', '関東草大会 月例杯', '関東各地(持ち回り)', '草大会', '毎月第3日曜', 'エンジョイ層から競技層まで幅広く参加できる気軽な月例大会。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_11', '名古屋ピックルフェスティバル', '愛知県名古屋市', '草大会', '毎年9月', '東海地方最大の草大会。体験会やメーカーブースも多数出展。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_12', '大阪ミックスダブルスオープン', '大阪府', '草大会', '毎年3月', 'ミックスダブルス限定の人気大会。初心者カテゴリあり。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_13', '札幌インドアカップ', '北海道札幌市', '草大会', '毎年1月', '冬の北海道で開催されるインドア大会。雪景色とピックルボールの組み合わせがユニーク。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_14', '福岡サンシャインオープン', '福岡県福岡市', '草大会', '毎年11月', '九州最大規模のピックルボール大会。');
INSERT INTO massive_salvage_tournaments (id, name, location, type, schedule, description) VALUES ('tour_15', 'Spanish Pickleball Open', 'バルセロナ, スペイン', '国際(欧州)', '毎年6月', 'ヨーロッパで急成長中のピックルボールシーンを象徴する大会。');
