INSERT INTO associations (id, name, acronym, country, description, website_url, is_hq_facility_id) VALUES ('assoc_jpa', 'Japan Pickleball Association (JPA)', 'JPA', 'Japan', '日本国内のピックルボール普及と競技力向上を目的とする代表的な団体。全日本選手権の主催や、指導者・レフェリーの育成・公認を行っている。', 'https://japanpickleball.org/', 'facility_ariake_tennis_forest');
INSERT INTO associations (id, name, acronym, country, description, website_url, is_hq_facility_id) VALUES ('assoc_usap', 'USA Pickleball', 'USAP', 'USA', 'アメリカにおけるピックルボールの国内競技統括団体。ルール改定や用具認証の中心的な役割を担い、世界各国で基準として採用される『USAP認定』を発行している。', 'https://usapickleball.org/', NULL);
INSERT INTO brands (id, name, country, description, website_url) VALUES ('brand_joola', 'JOOLA', 'Germany / USA', '卓球ブランドとしての世界的な実績を背景にピックルボール界に参入。Ben Johnsを筆頭にトッププロと契約し、最強のパワーパドル「Perseus」シリーズ等で市場を席巻している。', 'https://joolausa.com/');
INSERT INTO brands (id, name, country, description, website_url) VALUES ('brand_selkirk', 'Selkirk Sport', 'USA', '「We Are Pickleball」を掲げるピックルボール専業のトップブランド。品質に徹底的にこだわり、生涯保証（Lifetime Warranty）を提供している。VANGUARDやLUXXシリーズが有名。', 'https://www.selkirk.com/');
INSERT INTO brands (id, name, country, description, website_url) VALUES ('brand_franklin', 'Franklin Sports', 'USA', '全米オープンの公式球「X-40」を製造する総合スポーツメーカー。パドルでもFS Tourシリーズなど高品質かつ手頃な価格帯のギアを多数展開している。', 'https://franklinsports.com/');
INSERT INTO brands (id, name, country, description, website_url) VALUES ('brand_crbn', 'CRBN', 'USA', 'カーボンファイバー表面を採用した「生カーボン」パドルの先駆者。強烈なスピン性能を求める競技者から絶大な支持を得ている。', 'https://crbnpickleball.com/');
INSERT INTO gears_accessories (id, brand_name, product_name, price, category, specific_features, color_variations, amazon_url, rakuten_url, yahoo_url) VALUES ('acc_001', 'Tourna', 'Mega Tac (ウェットタイプ・オーバーグリップ)', 1200, 'グリップテープ', '圧倒的な吸い付きとウェット感。手汗をかかないインドア向け。', 'ホワイト, ブルー, ブラック', 'https://amazon.co.jp/dp/dummy_tourna', 'https://rakuten.co.jp/dummy_tourna', '');
INSERT INTO gears_accessories (id, brand_name, product_name, price, category, specific_features, color_variations, amazon_url, rakuten_url, yahoo_url) VALUES ('acc_002', 'CRBN', 'Pickleball Lead Tape (鉛テープ)', 2500, 'カスタマイズ用品', '3g単位でカット済み。パドルのスイートスポット拡大とパワーアップ用。', 'ブラック', 'https://amazon.co.jp/dp/dummy_crbn_tape', '', '');
